function flattenListings() {
  const out = [];
  for (const city of ADDRESS_CITIES) {
    const pack = CITY_LISTING_PACKS[`${city.country}|${city.name_en}`];
    if (!pack) continue;
    for (const e of pack.entries) {
      out.push({
        country: city.country,
        city: city.name_en,
        kind: e.kind,
        title: e.title,
        line1: e.line1,
        district: e.district,
        postal_code: e.postal_code,
        phone_area: pack.phone_area,
        phone_sample: e.phone_sample,
      });
    }
  }
  return out;
}

/** @type {Array<{country:string,city:string,kind:'rent'|'sale',title:string,line1:string,district:string,postal_code:string,phone_area:string,phone_sample:string}>} */
export const ADDRESS_LISTINGS = flattenListings();
